styles:
    *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }

    :root {
      --sidebar-bg: #DAE4F8;
      --main-bg: #FFFCF8;
      --blue: #448AFF;
      --blue-dark: #3a7aee;
      --blue-ring: rgba(68, 138, 255, 0.18);
      --text: #1a1a1a;
      --muted: #6b6b6b;
      --card-hover: #FFEED5;
      --banner-bg: #c5d9fc;
      --pending-bg: #FFE082;
      --input-bg: rgba(68, 138, 255, 0.06);
      --input-radius: 10px;
      --sidebar-width: 248px;
      --font: 'Montserrat', sans-serif;
    }

    html, body { height: 100%; }

    body {
      font-family: var(--font);
      background: var(--main-bg);
      color: var(--text);
      -webkit-font-smoothing: antialiased;
    }

    .app { display: flex; min-height: 100vh; }

    /* ── Sidebar ── */
    .sidebar {
      width: var(--sidebar-width);
      flex-shrink: 0;
      background: var(--sidebar-bg);
      display: flex;
      flex-direction: column;
      padding: 28px 20px 32px;
      min-height: 100vh;
      transition: width 0.22s ease, padding 0.22s ease;
      position: relative;
    }

    .sidebar__collapse {
      position: absolute;
      top: 14px;
      right: 12px;
      width: 34px;
      height: 34px;
      border: none;
      border-radius: 8px;
      background: transparent;
      color: var(--blue);
      cursor: pointer;
      display: flex;
      align-items: center;
      justify-content: center;
      padding: 0;
      transition: background 0.15s ease;
    }

    .sidebar__collapse:hover { background: rgba(68, 138, 255, 0.12); }
    .sidebar__collapse svg { width: 22px; height: 22px; display: block; }
    .app.is-sidebar-collapsed .sidebar__collapse { display: none; }

    .sidebar__toggle {
      width: 54px;
      height: 54px;
      margin: 0 auto 18px;
      border: none;
      border-radius: 16px;
      background: rgba(68, 138, 255, 0.12);
      display: none;
      align-items: center;
      justify-content: center;
      cursor: pointer;
      transition: background 0.15s ease;
    }

    .app.is-sidebar-collapsed .sidebar__toggle { display: flex; }
    .sidebar__toggle:hover { background: rgba(68, 138, 255, 0.18); }

    .sidebar__toggle img {
      width: 32px;
      height: 32px;
      object-fit: contain;
      filter: brightness(0) saturate(100%) invert(59%) sepia(92%) saturate(2775%) hue-rotate(196deg) brightness(101%) contrast(101%);
    }

    .sidebar__brand {
      display: flex;
      flex-direction: column;
      align-items: center;
      text-align: center;
      margin-bottom: 36px;
    }

    .sidebar__logo {
      width: 120px;
      height: auto;
      display: block;
      filter: brightness(0) saturate(100%) invert(59%) sepia(92%) saturate(2775%) hue-rotate(196deg) brightness(101%) contrast(101%);
      margin-bottom: 4px;
    }

    .sidebar__title {
      font-size: 15px;
      font-weight: 800;
      color: var(--blue);
      letter-spacing: 0.06em;
    }

    .nav { list-style: none; display: flex; flex-direction: column; gap: 6px; }

    .nav a {
      display: flex;
      align-items: center;
      gap: 12px;
      padding: 12px 16px;
      border-radius: 12px;
      color: var(--blue);
      font-size: 14px;
      font-weight: 600;
      text-decoration: none;
      transition: background 0.15s ease;
    }

    .nav a svg { width: 20px; height: 20px; flex-shrink: 0; stroke: currentColor; fill: none; }
    .nav a:hover:not(.is-active) { background: rgba(68, 138, 255, 0.12); }
    .nav a.is-active { background: var(--blue); color: #fff; }
    .nav a.is-active svg { stroke: #fff; }
    .nav a .nav-icon--saved { stroke: none; }
    .nav a .nav-icon--saved path { fill: currentColor; }
    .nav a .nav-icon--attendance { stroke: none; }
    .nav a .nav-icon--attendance path { fill: currentColor; }
    .nav a .nav-icon--events { stroke: none; }
    .nav a .nav-icon--events path { fill: currentColor; }
    .nav a .nav-icon--home { stroke: none; }
    .nav a .nav-icon--home path { fill: currentColor; }
    .nav a .nav-icon--certificates { stroke: none; }
    .nav a .nav-icon--certificates path { fill: currentColor; }
    .nav a.is-active [class*="nav-icon--"] > g { filter: none; }

    .sidebar__spacer { flex: 1; min-height: 24px; }
    .nav--bottom { margin-top: auto; padding-top: 16px; }

    .app.is-sidebar-collapsed .sidebar { width: 102px; padding: 28px 12px 24px; }
    .app.is-sidebar-collapsed .sidebar__brand { display: none; }
    .app.is-sidebar-collapsed .nav a { justify-content: center; gap: 0; padding: 14px 0; font-size: 0; }
    .app.is-sidebar-collapsed .nav a svg { width: 24px; height: 24px; }
    .app.is-sidebar-collapsed .nav a.is-active { width: 56px; margin: 0 auto; }

    .main {
      flex: 1;
      min-width: 0;
      overflow-y: auto;
      padding: 32px 40px 48px;
    }

    .main__top {
      display: flex;
      align-items: center;
      justify-content: space-between;
      gap: 16px;
      margin-bottom: 24px;
    }

    .main__greeting {
      font-size: clamp(1.75rem, 3vw, 2.25rem);
      font-weight: 700;
      color: var(--blue);
      line-height: 1.15;
      letter-spacing: -0.02em;
    }

    .main__tools {
      display: flex;
      align-items: center;
      gap: 14px;
    }

    .main__user-name {
      font-size: 14px;
      font-weight: 600;
      color: var(--blue);
      white-space: nowrap;
    }

    .tool-btn {
      width: 40px;
      height: 40px;
      border: none;
      border-radius: 50%;
      background: transparent;
      cursor: pointer;
      display: flex;
      align-items: center;
      justify-content: center;
      color: var(--blue);
      flex-shrink: 0;
      text-decoration: none;
    }

    .tool-btn:hover { background: rgba(68, 138, 255, 0.1); }
    .tool-btn--avatar { background: #c5d9fc; }
    .tool-btn--help { background: #c5d9fc; color: #fff; }
    .tool-btn--help:hover { background: #b5cffc; color: #fff; }
    .tool-btn--help svg { width: 22px; height: 22px; flex-shrink: 0; }
    .tool-btn svg { width: 22px; height: 22px; }

    .profile-hero {
      position: relative;
      margin-bottom: 88px;
    }

    .profile-banner {
      position: relative;
      height: 180px;
      border-radius: 20px;
      overflow: hidden;
      background: linear-gradient(135deg, #c5d9fc 0%, #dae4f8 45%, #e8eef8 100%);
      background-size: cover;
      background-position: center;
      background-repeat: no-repeat;
      box-shadow: 0 8px 28px rgba(0, 40, 90, 0.08);
    }

    .profile-banner.has-photo {
      background-color: #e8eef8;
    }

    .profile-banner.has-photo .profile-banner__cover {
      display: none;
    }

    .profile-banner__cover {
      position: absolute;
      inset: 0;
      background:
        radial-gradient(circle at 85% 20%, rgba(68, 138, 255, 0.18) 0%, transparent 42%),
        radial-gradient(circle at 12% 80%, rgba(197, 217, 252, 0.9) 0%, transparent 48%),
        linear-gradient(135deg, #b8cff9 0%, #dae4f8 55%, #f0f5fc 100%);
    }

    .profile-banner__cover-text {
      display: none;
    }

    .profile-banner__upload {
      position: absolute;
      top: 16px;
      right: 16px;
      display: inline-flex;
      align-items: center;
      gap: 6px;
      padding: 8px 14px;
      border: 1.5px solid rgba(255, 255, 255, 0.65);
      border-radius: 999px;
      background: rgba(255, 255, 255, 0.82);
      backdrop-filter: blur(8px);
      color: var(--blue);
      font-family: var(--font);
      font-size: 12px;
      font-weight: 600;
      cursor: pointer;
      transition: background 0.15s ease, border-color 0.15s ease, box-shadow 0.15s ease;
    }

    .profile-banner__upload:hover {
      background: #fff;
      border-color: #fff;
      box-shadow: 0 4px 14px rgba(68, 138, 255, 0.18);
    }

    .profile-hero__identity {
      position: absolute;
      left: 28px;
      bottom: -52px;
      display: flex;
      align-items: flex-end;
      gap: 16px;
      z-index: 2;
    }

    .profile-avatar-wrap {
      position: relative;
      flex-shrink: 0;
    }

    .profile-avatar {
      width: 104px;
      height: 104px;
      border-radius: 50%;
      object-fit: cover;
      display: flex;
      align-items: center;
      justify-content: center;
      flex-shrink: 0;
      border: 4px solid var(--main-bg);
      box-shadow: 0 8px 24px rgba(0, 40, 90, 0.12);
      background: linear-gradient(135deg, #e8eef8 0%, #d4e2f7 100%);
    }

    .profile-avatar--placeholder {
      font-size: 40px;
    }

    .profile-avatar.is-photo {
      font-size: 0;
    }

    .profile-avatar__upload {
      position: absolute;
      right: 2px;
      bottom: 2px;
      width: 32px;
      height: 32px;
      border: 2px solid var(--main-bg);
      border-radius: 50%;
      background: var(--blue);
      color: #fff;
      cursor: pointer;
      display: flex;
      align-items: center;
      justify-content: center;
      transition: background 0.15s ease, transform 0.15s ease;
    }

    .profile-avatar__upload:hover {
      background: var(--blue-dark);
      transform: scale(1.05);
    }

    .profile-avatar__upload svg {
      width: 14px;
      height: 14px;
    }

    .profile-upload-input {
      display: none;
    }

    .profile-grid {
      display: grid;
      grid-template-columns: 1fr 320px;
      gap: 24px;
      align-items: start;
    }

    .profile-card {
      background: #fff;
      border: 1.5px solid transparent;
      border-radius: 20px;
      box-shadow: 0 8px 24px rgba(0, 40, 90, 0.08);
      padding: 28px 28px 32px;
      transition: box-shadow 0.18s ease;
    }

    .profile-card:hover {
      box-shadow: 0 12px 30px rgba(68, 138, 255, 0.1);
    }

    .profile-card--main {
      padding-top: 28px;
    }

    .profile-card--side {
      padding: 22px 22px 24px;
      margin-bottom: 16px;
    }

    .profile-card--side:last-child { margin-bottom: 0; }

    .profile-fields-grid {
      display: grid;
      grid-template-columns: repeat(2, minmax(0, 1fr));
      gap: 18px 20px;
      margin-bottom: 8px;
    }

    .profile-fields-grid .profile-field--full {
      grid-column: 1 / -1;
    }

    .profile-field {
      margin-bottom: 0;
    }

    .profile-field__label {
      display: block;
      font-size: 11px;
      font-weight: 700;
      color: var(--muted);
      text-transform: uppercase;
      letter-spacing: 0.06em;
      margin-bottom: 8px;
    }

    .profile-field__input {
      width: 100%;
      height: 44px;
      border: 1.5px solid transparent;
      border-radius: var(--input-radius);
      padding: 0 14px;
      font-family: var(--font);
      font-size: 14px;
      font-weight: 600;
      color: var(--text);
      background: var(--input-bg);
      transition: border-color 0.15s ease, background 0.15s ease, box-shadow 0.15s ease;
    }

    .profile-field__input:hover {
      background: rgba(68, 138, 255, 0.09);
    }

    .profile-field__input:focus {
      outline: none;
      border-color: var(--blue);
      background: #fff;
      box-shadow: 0 0 0 3px var(--blue-ring);
    }

    .profile-field__input::placeholder {
      color: #b0b0b0;
      font-weight: 500;
    }

    .profile-field__input:read-only {
      pointer-events: none;
      background: transparent;
      border-color: transparent;
      padding-left: 0;
      cursor: default;
    }

    .profile-field__input:read-only:hover,
    .profile-field__input:read-only:focus {
      background: transparent;
      border-color: transparent;
      box-shadow: none;
    }

    .profile-hero:not(.is-editing) .profile-banner__upload,
    .profile-hero:not(.is-editing) .profile-avatar__upload {
      opacity: 0;
      pointer-events: none;
    }

    .profile-hero.is-editing .profile-banner__upload,
    .profile-hero.is-editing .profile-avatar__upload {
      opacity: 1;
      pointer-events: auto;
      transition: opacity 0.15s ease;
    }

    .profile-save-row {
      margin-top: 28px;
      padding-top: 22px;
      border-top: 1px solid rgba(68, 138, 255, 0.1);
      display: flex;
      align-items: center;
      justify-content: flex-end;
      gap: 12px;
    }

    .profile-save-hint {
      font-size: 12px;
      font-weight: 500;
      color: var(--muted);
    }

    .profile-save-hint.is-saved {
      color: var(--blue);
      font-weight: 600;
    }

    .btn-save-profile {
      padding: 11px 24px;
      border: none;
      border-radius: 999px;
      background: var(--blue);
      color: #fff;
      font-family: var(--font);
      font-size: 13px;
      font-weight: 700;
      cursor: pointer;
      transition: background 0.15s ease, box-shadow 0.15s ease, transform 0.15s ease;
    }

    .btn-save-profile:hover {
      background: var(--blue-dark);
      box-shadow: 0 6px 18px rgba(68, 138, 255, 0.28);
      transform: translateY(-1px);
    }

    .btn-save-profile.is-editing {
      background: var(--blue-dark);
    }

    .profile-section-title {
      display: flex;
      align-items: center;
      gap: 10px;
      font-size: 13px;
      font-weight: 700;
      color: var(--blue);
      text-transform: uppercase;
      letter-spacing: 0.08em;
      margin: 32px 0 20px;
    }

    .profile-section-title::after {
      content: '';
      flex: 1;
      height: 1px;
      background: rgba(68, 138, 255, 0.14);
    }

    .profile-about-grid {
      display: grid;
      grid-template-columns: repeat(2, minmax(0, 1fr));
      gap: 18px 20px;
    }

    .profile-about-grid .profile-field--full {
      grid-column: 1 / -1;
    }

    .profile-position-row {
      display: flex;
      align-items: center;
      gap: 10px;
      flex-wrap: wrap;
    }

    .profile-position-row .profile-field__input {
      flex: 1;
      min-width: 160px;
    }

    .tag-pending {
      display: inline-flex;
      align-items: center;
      padding: 5px 12px;
      border-radius: 999px;
      background: rgba(255, 224, 130, 0.55);
      font-size: 11px;
      font-weight: 700;
      color: #7a5a00;
      letter-spacing: 0.02em;
    }

    .side-card__title {
      font-size: 14px;
      font-weight: 700;
      color: var(--text);
      margin-bottom: 16px;
      letter-spacing: -0.01em;
    }

    .side-card__title--blue {
      color: var(--blue);
      text-decoration: none;
    }

    .stat-list { list-style: none; }

    .stat-list li {
      display: flex;
      align-items: center;
      justify-content: space-between;
      gap: 12px;
      padding: 12px 14px;
      font-size: 13px;
      font-weight: 500;
      color: var(--muted);
      background: var(--input-bg);
      border-radius: 12px;
      margin-bottom: 8px;
    }

    .stat-list li:last-child { margin-bottom: 0; }

    .stat-list__value {
      font-size: 15px;
      font-weight: 800;
      color: var(--blue);
      min-width: 28px;
      text-align: right;
    }

    .activity-list { list-style: none; }

    .activity-list li {
      position: relative;
      padding: 10px 0 10px 22px;
      font-size: 13px;
      font-weight: 500;
      color: var(--text);
      line-height: 1.45;
      border-bottom: 1px solid rgba(68, 138, 255, 0.08);
    }

    .activity-list li:last-child {
      border-bottom: none;
      padding-bottom: 0;
    }

    .activity-list li::before {
      content: '';
      position: absolute;
      left: 0;
      top: 16px;
      width: 8px;
      height: 8px;
      border-radius: 50%;
      background: var(--blue);
      box-shadow: 0 0 0 3px rgba(68, 138, 255, 0.15);
    }

    .settings-row {
      display: flex;
      align-items: center;
      justify-content: space-between;
      gap: 12px;
      padding: 12px 14px;
      border-radius: 12px;
      background: var(--input-bg);
    }

    .settings-row__label {
      font-size: 13px;
      font-weight: 600;
      color: var(--text);
    }

    .btn-change {
      padding: 8px 16px;
      border: 1.5px solid rgba(68, 138, 255, 0.35);
      border-radius: 999px;
      background: #fff;
      color: var(--blue);
      font-family: var(--font);
      font-size: 12px;
      font-weight: 700;
      cursor: pointer;
      white-space: nowrap;
      transition: background 0.15s ease, border-color 0.15s ease, box-shadow 0.15s ease;
    }

    .btn-change:hover {
      background: rgba(68, 138, 255, 0.08);
      border-color: var(--blue);
      box-shadow: 0 0 0 3px var(--blue-ring);
    }

    @media (max-width: 1024px) {
      .profile-grid { grid-template-columns: 1fr; }
      .profile-fields-grid,
      .profile-about-grid { grid-template-columns: 1fr; }
    }

    @media (max-width: 900px) {
      .app { flex-direction: column; }
      .sidebar { width: 100%; min-height: auto; flex-direction: row; flex-wrap: wrap; padding: 20px; }
      .sidebar__brand { flex-direction: row; gap: 12px; margin-bottom: 0; width: 100%; }
      .sidebar__collapse, .sidebar__toggle { display: none !important; }
      .nav { flex-direction: row; flex-wrap: wrap; width: 100%; }
      .sidebar__spacer, .nav--bottom { display: none; }
      .app.is-sidebar-collapsed .sidebar { width: 100%; padding: 20px; }
      .app.is-sidebar-collapsed .sidebar__brand { display: flex; }
      .app.is-sidebar-collapsed .nav a { font-size: 14px; gap: 12px; padding: 12px 16px; justify-content: flex-start; }
      .app.is-sidebar-collapsed .nav a.is-active { width: auto; margin: 0; }
      .main__user-name { display: none; }
      .main { padding: 24px 20px 40px; }
      .profile-hero { margin-bottom: 72px; }
      .profile-banner { height: 150px; border-radius: 16px; }
      .profile-hero__identity { left: 20px; bottom: -44px; }
      .profile-avatar { width: 88px; height: 88px; }
    }

