(function () {
      var app = document.querySelector('.app');
      var toggle = document.getElementById('sidebar-toggle');
      var collapse = document.getElementById('sidebar-collapse');
      var storageKey = 'dc_sidebar_collapsed';

      function setSidebarCollapsed(collapsed) {
        app.classList.toggle('is-sidebar-collapsed', collapsed);
        localStorage.setItem(storageKey, collapsed);
      }

      if (localStorage.getItem(storageKey) === 'true' && window.innerWidth > 900) {
        setSidebarCollapsed(true);
      }

      collapse.addEventListener('click', function () {
        if (window.innerWidth <= 900) return;
        setSidebarCollapsed(true);
      });

      toggle.addEventListener('click', function () {
        if (window.innerWidth <= 900) return;
        setSidebarCollapsed(false);
      });

      var bannerEl = document.getElementById('profile-banner');
      var bannerInput = document.getElementById('banner-photo-input');
      var bannerBtn = document.getElementById('banner-upload-btn');
      var avatarEl = document.getElementById('profile-avatar');
      var avatarInput = document.getElementById('avatar-photo-input');
      var avatarBtn = document.getElementById('avatar-upload-btn');
      function getAccountKey() {
        try {
          var authRaw = localStorage.getItem('dcspace_auth');
          if (authRaw) {
            var auth = JSON.parse(authRaw);
            var seed = (auth && auth.user && (auth.user.id || auth.user.email)) || '';
            if (seed) {
              return String(seed).trim().toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/^-+|-+$/g, '') || 'guest';
            }
          }
        } catch (err) { /* ignore */ }
        var email = localStorage.getItem('dcspaceStudentEmail') || '';
        return String(email).trim().toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/^-+|-+$/g, '') || 'guest';
      }

      function scopedKey(base) {
        return base + ':' + getAccountKey();
      }

      function getBannerStorageKey() { return scopedKey('dcspaceProfileCoverImage'); }
      function getAvatarStorageKey() { return scopedKey('dcspaceProfilePhotoImage'); }
      function getInfoStorageKey() { return scopedKey('dc_profile_info'); }

      // Remove legacy shared keys so photos never leak across accounts.
      try {
        localStorage.removeItem('dc_profile_banner');
        localStorage.removeItem('dc_profile_avatar');
        localStorage.removeItem('dc_profile_info');
      } catch (err) { /* ignore */ }

      var bannerStorageKey = getBannerStorageKey();
      var avatarStorageKey = getAvatarStorageKey();
      var infoStorageKey = getInfoStorageKey();

      var defaultProfile = {
        name: 'First Name Last Name',
        email: 'school@sdca.edu.ph',
        studentNumber: '0000-00000',
        course: 'BSIT',
        department: 'SCMCS',
        organization: 'None',
        orgRole: 'None',
        orgPosition: 'Organization Position'
      };

      var profileInputs = document.querySelectorAll('.profile-field__input[data-field]');
      var aboutTitleEl = document.getElementById('profile-about-title');
      var saveBtn = document.getElementById('save-profile-btn');
      var saveHint = document.getElementById('profile-save-hint');
      var profileHero = document.getElementById('profile-hero');
      var profileMainCard = document.querySelector('.profile-card--main');
      var saveHintTimer;
      var isEditing = false;

      function setEditMode(editing) {
        isEditing = editing;
        profileMainCard.classList.toggle('is-editing', editing);
        profileHero.classList.toggle('is-editing', editing);
        profileInputs.forEach(function (input) {
          input.readOnly = !editing;
        });
        saveBtn.textContent = editing ? 'Save' : 'Edit';
        saveBtn.classList.toggle('is-editing', editing);
        saveBtn.setAttribute('aria-pressed', editing ? 'true' : 'false');
        if (!editing) {
          saveHint.textContent = '';
          saveHint.classList.remove('is-saved');
        }
      }

      function getFirstName(fullName) {
        var parts = String(fullName || '').trim().split(/\s+/);
        return parts[0] || 'First Name';
      }

      function updateAboutTitle() {
        var nameInput = document.querySelector('[data-field="name"]');
        aboutTitleEl.textContent = 'About ' + getFirstName(nameInput ? nameInput.value : defaultProfile.name);
      }

      function collectProfileInfo() {
        var data = {};
        profileInputs.forEach(function (input) {
          data[input.getAttribute('data-field')] = input.value.trim();
        });
        return data;
      }

      function applyProfileInfo(data) {
        profileInputs.forEach(function (input) {
          var key = input.getAttribute('data-field');
          if (data[key] !== undefined && data[key] !== '') {
            input.value = data[key];
          }
        });
        updateAboutTitle();
      }

      function saveProfileInfo(showMessage) {
        var data = collectProfileInfo();
        try {
          localStorage.setItem(getInfoStorageKey(), JSON.stringify(data));
          if (showMessage) {
            saveHint.textContent = 'Changes saved successfully.';
            saveHint.classList.add('is-saved');
            clearTimeout(saveHintTimer);
            saveHintTimer = setTimeout(function () {
              saveHint.textContent = '';
              saveHint.classList.remove('is-saved');
            }, 2500);
          }
        } catch (err) { /* ignore */ }
      }

      function readAuthProfile() {
        try {
          var authRaw = localStorage.getItem('dcspace_auth');
          if (authRaw) {
            var auth = JSON.parse(authRaw);
            var user = auth && auth.user ? auth.user : null;
            if (user) {
              return {
                name: (user.fullName || ((user.firstName || '') + ' ' + (user.lastName || '')).trim()),
                email: user.email || '',
                studentNumber: user.studentNumber || '',
                course: user.course || '',
                department: user.school || '',
                organization: user.organizationPart || '',
                orgRole: user.organizationRole || '',
                orgPosition: user.organizationRole || '',
                rfidNumber: user.rfidNumber || '',
                accountType: user.role === 'faculty' ? 'Faculty' : 'Student'
              };
            }
          }
        } catch (err) { /* ignore */ }

        var firstName = localStorage.getItem('dcspaceFirstName') || '';
        var lastName = localStorage.getItem('dcspaceLastName') || '';
        var email = localStorage.getItem('dcspaceStudentEmail') || '';
        if (!firstName && !lastName && !email) return null;

        var role = localStorage.getItem('dcspaceAccountType') || 'student';
        return {
          name: (firstName + ' ' + lastName).trim(),
          email: email,
          studentNumber: localStorage.getItem('dcspaceStudentNumber') || '',
          course: localStorage.getItem('dcspaceCourse') || '',
          department: localStorage.getItem('dcspaceSchool') || '',
          organization: localStorage.getItem('dcspaceOrganizationPart') || '',
          orgRole: localStorage.getItem('dcspaceOrganizationRole') || '',
          orgPosition: localStorage.getItem('dcspaceOrganizationRole') || '',
          rfidNumber: localStorage.getItem('dcspaceRfidNumber') || '',
          accountType: role === 'faculty' ? 'Faculty' : 'Student'
        };
      }

      function loadProfileInfo() {
        var authProfile = readAuthProfile();
        var localProfile = null;
        try {
          var raw = localStorage.getItem(getInfoStorageKey());
          if (raw) localProfile = JSON.parse(raw);
        } catch (err) { /* ignore */ }

        if (authProfile) {
          applyProfileInfo(Object.assign({}, defaultProfile, localProfile || {}, authProfile));
          var nameEls = document.querySelectorAll('.main__user-name');
          nameEls.forEach(function (el) { el.textContent = authProfile.name || 'Your Name'; });
          return;
        }

        if (localProfile) {
          applyProfileInfo(localProfile);
          return;
        }
        applyProfileInfo(defaultProfile);
      }

      profileInputs.forEach(function (input) {
        input.addEventListener('input', function () {
          if (!isEditing) return;
          if (input.getAttribute('data-field') === 'name') updateAboutTitle();
        });
      });

      saveBtn.addEventListener('click', function () {
        if (!isEditing) {
          setEditMode(true);
          var firstInput = profileInputs[0];
          if (firstInput) firstInput.focus();
          return;
        }
        saveProfileInfo(true);
        setEditMode(false);
      });

      loadProfileInfo();
      setEditMode(false);

      function applyBannerImage(dataUrl) {
        bannerEl.style.backgroundImage = 'url("' + dataUrl + '")';
        bannerEl.classList.add('has-photo');
      }

      function applyAvatarImage(dataUrl) {
        avatarEl.style.backgroundImage = 'url("' + dataUrl + '")';
        avatarEl.style.backgroundSize = 'cover';
        avatarEl.style.backgroundPosition = 'center';
        avatarEl.textContent = '';
        avatarEl.classList.add('is-photo');
        avatarEl.setAttribute('aria-label', 'Uploaded profile photo');
      }

      function readImageFile(file, onLoad) {
        if (!file || !file.type.match(/^image\//)) return;
        var reader = new FileReader();
        reader.onload = function (e) {
          onLoad(e.target.result);
        };
        reader.readAsDataURL(file);
      }

      bannerBtn.addEventListener('click', function () {
        bannerInput.click();
      });

      bannerInput.addEventListener('change', function () {
        var file = bannerInput.files && bannerInput.files[0];
        if (!file) return;
        readImageFile(file, function (dataUrl) {
          applyBannerImage(dataUrl);
          try { localStorage.setItem(getBannerStorageKey(), dataUrl); } catch (err) { /* quota */ }
        });
        bannerInput.value = '';
      });

      avatarBtn.addEventListener('click', function () {
        avatarInput.click();
      });

      avatarInput.addEventListener('change', function () {
        var file = avatarInput.files && avatarInput.files[0];
        if (!file) return;
        readImageFile(file, function (dataUrl) {
          applyAvatarImage(dataUrl);
          try { localStorage.setItem(getAvatarStorageKey(), dataUrl); } catch (err) { /* quota */ }
        });
        avatarInput.value = '';
      });

      function clearBannerImage() {
        bannerEl.style.backgroundImage = '';
        bannerEl.classList.remove('has-photo');
      }

      function clearAvatarImage() {
        avatarEl.style.backgroundImage = '';
        avatarEl.classList.remove('is-photo');
        if (!avatarEl.textContent || !avatarEl.textContent.trim()) {
          avatarEl.textContent = '🐱';
        }
      }

      function loadAccountPhotos() {
        var bannerFromAuth = '';
        var avatarFromAuth = '';
        try {
          var authRaw = localStorage.getItem('dcspace_auth');
          if (authRaw) {
            var auth = JSON.parse(authRaw);
            if (auth && auth.user) {
              bannerFromAuth = auth.user.bannerUrl || '';
              avatarFromAuth = auth.user.photoUrl || '';
            }
          }
        } catch (err) { /* ignore */ }

        try {
          var savedBanner = bannerFromAuth || localStorage.getItem(getBannerStorageKey()) || '';
          if (savedBanner) applyBannerImage(savedBanner);
          else clearBannerImage();

          var savedAvatar = avatarFromAuth || localStorage.getItem(getAvatarStorageKey()) || '';
          if (savedAvatar) applyAvatarImage(savedAvatar);
          else clearAvatarImage();
        } catch (err) { /* ignore */ }
      }

      loadAccountPhotos();
    })();
